import type { NextRequest } from 'next/server'

const LOCALES = ['es', 'en', 'nl', 'de']
const DEFAULT_LOCALE = 'es'

/**
 * Detects preferred locale from Accept-Language header.
 */
function detectLocaleFromHeader(acceptLanguage: string | undefined): string | null {
  if (!acceptLanguage) return null
  const prefs = acceptLanguage.split(',').map(s => s.split(';')[0].trim().toLowerCase())
  for (const lang of prefs) {
    if (lang.startsWith('nl')) return 'nl'
    if (lang.startsWith('de')) return 'de'
    if (lang.startsWith('en')) return 'en'
    if (lang.startsWith('es')) return 'es'
  }
  return null
}

export function middleware(request: NextRequest) {
  const { pathname } = request.nextUrl

  // Skip API routes, sitemap, static files, _next
  if (
    pathname.startsWith('/api/') ||
    pathname.startsWith('/_next/') ||
    pathname === '/sitemap.xml' ||
    pathname === '/robots.txt' ||
    pathname.startsWith('/images/') ||
    pathname.startsWith('/favicon') ||
    pathname === '/' ||
    LOCALES.some(loc => pathname === `/${loc}` || pathname.startsWith(`/${loc}/`))
  ) {
    // If already has locale prefix, set cookie and continue
    const parts = pathname.split('/').filter(Boolean)
    if (LOCALES.includes(parts[0])) {
      const response = NextResponse.next()
      response.cookies.set('NEXT_LOCALE', parts[0], {
        path: '/',
        maxAge: 60 * 60 * 24 * 365,
        sameSite: 'lax',
      })
      return response
    }
    return NextResponse.next()
  }

  // Determine locale: URL prefix > cookie > Accept-Language > default
  let locale: string = DEFAULT_LOCALE

  const cookieLocale = request.cookies.get('NEXT_LOCALE')?.value
  if (cookieLocale && LOCALES.includes(cookieLocale)) {
    locale = cookieLocale
  }

  // Accept-Language only if no cookie set
  if (!cookieLocale) {
    const detected = detectLocaleFromHeader(request.headers.get('accept-language') || undefined)
    if (detected) locale = detected
  }

  // Redirect to locale-prefixed path
  const url = request.nextUrl.clone()
  url.pathname = `/${locale}${pathname === '/' ? '' : pathname}`
  const response = NextResponse.redirect(url)
  response.cookies.set('NEXT_LOCALE', locale, {
    path: '/',
    maxAge: 60 * 60 * 24 * 365,
    sameSite: 'lax',
  })
  return response
}

export const config = {
  matcher: [
    '/((?!api|_next|images|favicon).*)',
  ],
}
"}

