{"content": "import { MetadataRoute } from 'next'
import { readdirSync } from 'fs'

const BASE_URL = 'https://nexa.paragu-ai.com'
const LOCALES = ['es', 'en', 'nl', 'de']

function getAllPageSlugs(): string[] {
  const pagesDir = process.cwd() + '/nexa-pages'
  const files = readdirSync(pagesDir)
  return files
    .filter(f => f.endsWith('.json'))
    .map(f => f.replace('.json', ''))
    .filter(slug => slug !== 'home')
}

export default function sitemap(): MetadataRoute.Sitemap {
  const slugs = getAllPageSlugs()
  const entries: MetadataRoute.Sitemap = []

  for (const locale of LOCALES) {
    // Home page
    const homeAlternates: Record<string, string> = {}
    for (const altLoc of LOCALES) {
      homeAlternates[altLoc] = `${BASE_URL}/${altLoc}`
    }
    entries.push({
      url: `${BASE_URL}/${locale}`,
      lastModified: new Date(),
      changeFrequency: 'weekly',
      priority: 1.0,
      alternates: { languages: homeAlternates },
    })

    // Slug pages
    for (const slug of slugs) {
      const slugAlternates: Record<string, string> = {}
      for (const altLoc of LOCALES) {
        slugAlternates[altLoc] = `${BASE_URL}/${altLoc}/${slug}`
      }
      entries.push({
        url: `${BASE_URL}/${locale}/${slug}`,
        lastModified: new Date(),
        changeFrequency: 'monthly',
        priority: 0.8,
        alternates: { languages: slugAlternates },
      })
    }
  }

  return entries
}
